const { query, validationResult } = require('express-validator');

app.get('/users',
  query('id').optional().isInt().toInt(),
  query('name').optional().isAlphanumeric().trim().escape(),
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    // ... handle request
  }
);
```

---

### 🟡 Low Severity / Best Practices

#### 8. Information Leakage via Error Handling

Express's default error handler exposes stack traces in development mode. There's no custom error handler.

```js
// ✅ Add a global error handler that doesn't leak internals
app.use((err, req, res, next) => {
  console.error(err.stack);  // Log internally
  res.status(err.status || 500).json({
